<script setup lang="ts">import { computed, ref } from 'vue';import { downloadFile, fileDownloadUrl } from '../api/client';import MarkdownIt from 'markdown-it';const props=defineProps<{content:string;teamId:number}>();const downloadError=ref('');const md=new MarkdownIt({html:false,linkify:true,breaks:true});const fallback=md.renderer.rules.link_open;md.renderer.rules.link_open=(tokens,idx,options,env,self)=>{tokens[idx].attrSet('target','_blank');tokens[idx].attrSet('rel','noopener noreferrer');return fallback?fallback(tokens,idx,options,env,self):self.renderToken(tokens,idx,options);};const escaped=(value:string)=>value.replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]||c));/* 审计 L14 不变量：注入 v-html 的所有插值必须转义/编码——path 经 fileDownloadUrl 的 encodeURIComponent 编码，name/size 经 escaped()/Number 处理，改动此模板时务必维持该不变量，否则引入 XSS。 */const html=computed(()=>{const source=props.content||'';const rendered=md.render(source);const token=/\[文件:([^\]]+)\]([^|\n]+)(?:\|([\d.]+))?/g;return rendered.replace(token,(_all,path,name,size)=>`<a class="file-token" href="${fileDownloadUrl(path,props.teamId)}" data-path="${escaped(path)}" target="_blank" rel="noopener"><b>卷</b><span>${escaped(name.trim())}</span>${size?`<small>${Math.max(1,Math.round(Number(size)/1024))}KB</small>`:''}</a>`);});async function handleClick(event:MouseEvent){const target=(event.target as HTMLElement).closest<HTMLAnchorElement>('a.file-token');if(!target)return;event.preventDefault();downloadError.value='';try{await downloadFile(String(target.dataset.path||''),props.teamId);}catch(error){downloadError.value=error instanceof Error?error.message:'文件下载失败';}}</script>
<template><div><div class="markdown" v-html="html" @click="handleClick"></div><p v-if="downloadError" class="file-download-error" role="alert">{{ downloadError }}</p></div></template>
